/**
 * Compiled regex for fast emoji detection.
 * \\uXXXX → real chars (except \\u002a which is `*` and is left as escape).
 */
export const compactEmojiPattern: RegExp = new RegExp(
  emojiPattern.replace(/\\u(?!002a)([0-9A-F]{4})/gi, (_m, g1) =>
    String.fromCharCode(parseInt(g1, 16)),
  ),
)

/** Check if `text` starts with an emoji. */
export function startsWithEmoji(text: string): RegExpMatchArray | null {
  const match = text.match(compactEmojiPattern)
  return match && match.index === 0 ? match : null
}

/** Return the first emoji in `text`, or null. */
export function getFirstEmoji(text: string): string | null {
  if (!text) return null
  const match = text.match(compactEmojiPattern)
  return match ? match[0] : null
}

/** Strip a leading emoji (and one trailing space) from `text`. */
export function trimFirstEmoji(text: string): string {
  if (!text) return ''
  return text.replace(new RegExp(`^(${compactEmojiPattern.source})\\s*`), '')
}

